export default class Clock extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        time {
          font-family: var(--font-family);
          font-size: 18px;
          display: inline-block;
          max-width: min-content;
          text-align: left;
        } 
      </style>
      <time></time>
    `
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
    setInterval(this.render, 1000);
  }

  render = () => {
    this.shadowRoot.querySelector("time").innerHTML = new Intl.DateTimeFormat('default',
      {
        hour12: true,
        hour: 'numeric',
        minute: 'numeric',
        second: 'numeric'
      }).format(new Date());
  }
}
